import React, { Component } from "react";
import styled from "styled-components";
import styles from "../../styles/styles";

import WebPage from "../../components/webPage/WebPage";
import PageArticle from "../../components/pageArticle/PageArticle";
import Emoji from "../../components/emoji/Emoji";
// import { NULL } from "node-sass"

// getComputedStyle(document.documentElement).getPropertyValue('--my-variable-name'); // #999999

// https://davidwalsh.name/css-variables-javascript

const ColorBox = styled.div`
  height: 32px;
  width: 32px;
  background: var(${(props) => props.color});
`;

const ColorItem = styled.div`
  margin: var(--halfGutter);
  display: flex;
  flex-direction: row;
`;

class ColorExample extends Component {
  constructor() {
    super();

    this.css = null;
  }

  didComponentMount() {
    this.css = getComputedStyle(document.documentElement).getPropertyValue(
      this.props.color
    );
  }

  render() {
    // var css = this.getCSS()

    return (
      <ColorItem>
        <ColorBox color={this.props.color} />

        <code>{this.props.color}</code>

        <code>{this.css}</code>
      </ColorItem>
    );
  }
}

